+}
+
+.text-center h1 {
+    font-size: 2rem;
+    margin-bottom: 5px;
+}
+
+.text-center p {
+    letter-spacing: 1px;
+    font-size: 0.8rem;
+}
+
+/* ========================
+   CATEGORIES SECTION
+======================== */
+
+.categories-section {
+    margin: 80px 0;
+    padding: 0 20px;
+}
+
+.catagories-head {
+    padding: 10px 0 0 30px;
+    font-family: "DM Serif Display", serif;
+}
+
+.catagories-head span {
+    font-size: 12px;
+    color: #00D4FF;
+}
+
+.catagories-head h2 {
+    font-size: 30px;
+    color: #e8eafe;
+    font-weight: 300;
+}
+
+.categories {
+    padding: 20px;
+    display: grid;
+    grid-template-columns: repeat(4, 1fr);
+    gap: 30px;
+}
+
+.category-card {
+    background: #111827;
+    border: 1px solid #7A8399;
+    border-radius: 20px;
+    padding: 25px;
+    transition: 0.3s ease-in-out;
+}
+
+.category-card:hover {
+    background-color: #121e37;
+    border: 1px solid #00D4FF;
+}
+
+.card-icon {
+    padding: 5px;
+    margin-bottom: 10px;
+}
+
+.category-card h3 {
+    font-family: "DM Serif Display", serif;
+    font-weight: 300;
+    color: white;
+    margin-bottom: 10px;
+}
+
+.category-card p {
+    color: #9ca3af;
