+    margin-bottom: 10px;
+}
+
+.why-card p {
+    color: #94a3b8;
+    line-height: 1.8;
+}
+
+/* FIX: was .why-card .card-icon — that was correct, but ensure margin works */
+.why-card .card-icon,
+.resource-card a {
+    display: block;
+    margin-bottom: 10px;
+}
+
+/* ========================
+   CTA SECTION
+======================== */
+
+.cta {
+    margin: 20px 8%;
