+    font-family: 'Space Mono';
+    font-weight: 600;
+}
+
+.cta-btn:hover {
+    background: #0ea5e9;
+}
+
+
+/* ===== FOOTER ===== */
+.footer {
+    background: #020617;
+    font-size: 16px;
+    padding-top: 50px;
+    border-top: 1px solid rgba(255, 255, 255, .1);
+
+}
+
+.footer-container {
+    display: grid;
+    grid-template-columns: 2fr 1fr 1fr 1.2fr;
+    gap: 40px;
+    row-gap: 30px;
+    column-gap: 50px;
+    margin: 0px 50px;
+    color: #868fa1;
+
+}
+
+.footer-box h3,
+.footer-box h2 {
+    margin-bottom: 15px;
+    color: #007bff;
+}
+
+.footer-box .U h2 {
+    border-bottom: 2px solid;
+    text-align: center;
+
+}
+
+.footer-box .U p {
+    font-size: 14px;
+    text-align: center;
+
+}
+
+.footer-box ul {
+    list-style: none;
+
+
+}
+
+.footer-box ul li {
+
+    margin-bottom: 10px;
+    font-size: 14px;
+    font-weight: lighter;
+}
+
+.footer-box a {
+    color: #868fa1;
+
+    text-decoration: none;
+}
+
+.footer-box a:hover {
